import{_ as e,o as l,c as a,a2 as i}from"./chunks/framework.DnrXFDHb.js";const x=JSON.parse('{"title":"F01: 營收因子與定價權分析 - 財務分析專家 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/3135_凌航/20260430/F01_營收因子與定價權分析_財務分析專家.md","filePath":"審計報告庫/財務審計/3135_凌航/20260430/F01_營收因子與定價權分析_財務分析專家.md"}'),d={name:"審計報告庫/財務審計/3135_凌航/20260430/F01_營收因子與定價權分析_財務分析專家.md"};function n(r,t,s,o,h,g){return l(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="f01-營收因子與定價權分析-財務分析專家-審計報告" tabindex="-1">F01: 營收因子與定價權分析 - 財務分析專家 審計報告 <a class="header-anchor" href="#f01-營收因子與定價權分析-財務分析專家-審計報告" aria-label="Permalink to &quot;F01: 營收因子與定價權分析 - 財務分析專家 審計報告&quot;">​</a></h1><p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><hr><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>營收成長或衰退的實質因子分析：是由於「銷量增加 (Volume Up)」還是「單價調整 (Price Up)」？——透過拆解 P (價格) 與 V (銷量)，判定公司業績成長的真實驅動力。</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>凌航 2023-2025 營收成長以價格因子為絕對主驅動力（80-90%），2026Q1 價量齊揚為週期性脈衝。評級 B+。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">產業驅動因子</th><th style="text-align:left;">2024</th><th style="text-align:left;">2025</th><th style="text-align:left;">2026Q1</th></tr></thead><tbody><tr><td style="text-align:left;">DRAM 芯片 ASP YoY</td><td style="text-align:left;">+53%</td><td style="text-align:left;">+35%</td><td style="text-align:left;">+90-95% QoQ</td></tr><tr><td style="text-align:left;">NAND 芯片 ASP YoY</td><td style="text-align:left;">+77%</td><td style="text-align:left;">+29%</td><td style="text-align:left;">+55-60% QoQ</td></tr><tr><td style="text-align:left;">DDR5 佔比</td><td style="text-align:left;">~30%</td><td style="text-align:left;">55%</td><td style="text-align:left;">目標 70%</td></tr></tbody></table><h3 id="診斷見解" tabindex="-1">診斷見解 <a class="header-anchor" href="#診斷見解" aria-label="Permalink to &quot;診斷見解&quot;">​</a></h3><ol><li><strong>價格主導的營收成長</strong>：2023→2024 營收 +30.5%，加權 ASP 估計上漲 ~28%，銷量貢獻僅 ~8%。2024→2025 營收 +39.8%，加權 ASP 估計上漲 ~35%，銷量貢獻 ~13%。</li></ol><h3 id="診斷評級-b-持平偏上" tabindex="-1">診斷評級：B+（持平偏上） <a class="header-anchor" href="#診斷評級-b-持平偏上" aria-label="Permalink to &quot;診斷評級：B+（持平偏上）&quot;">​</a></h3><p>營收成長主要由 DRAM/NAND 報價上漲驅動，屬「成本推升型成長」，公司在供應鏈中議價能力有限。</p><hr><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="一、驅動因子權重-driver-weight" tabindex="-1">一、驅動因子權重 (Driver Weight) <a class="header-anchor" href="#一、驅動因子權重-driver-weight" aria-label="Permalink to &quot;一、驅動因子權重 (Driver Weight)&quot;">​</a></h3><p><strong>核心發現</strong>：2023-2025 價格貢獻 80-90%，銷量因子僅 10-20%。</p><table tabindex="0"><thead><tr><th style="text-align:left;">年度</th><th style="text-align:left;">營收成長</th><th style="text-align:left;">估計 ASP 變動</th><th style="text-align:left;">估計銷量變動</th><th style="text-align:left;">價格貢獻佔比</th><th style="text-align:left;">銷量貢獻佔比</th></tr></thead><tbody><tr><td style="text-align:left;">2023→2024</td><td style="text-align:left;">+30.5%</td><td style="text-align:left;">+28%</td><td style="text-align:left;">+2%</td><td style="text-align:left;">~92%</td><td style="text-align:left;">~8%</td></tr><tr><td style="text-align:left;">2024→2025</td><td style="text-align:left;">+39.8%</td><td style="text-align:left;">+35%</td><td style="text-align:left;">+4%</td><td style="text-align:left;">~88%</td><td style="text-align:left;">~12%</td></tr><tr><td style="text-align:left;">2025Q1→2026Q1</td><td style="text-align:left;">+178%</td><td style="text-align:left;">+55%</td><td style="text-align:left;">+80%</td><td style="text-align:left;">~31%</td><td style="text-align:left;">~69%</td></tr></tbody></table><p><strong>估算方法</strong>：以 TrendForce DRAM/NAND 合約價變動為基準，考量芯片成本佔比（~75-80%）及 DDR5 佔比提升，推估模組 ASP 變動率。</p><h3 id="二、獲利品質連動-margin-linkage" tabindex="-1">二、獲利品質連動 (Margin Linkage) <a class="header-anchor" href="#二、獲利品質連動-margin-linkage" aria-label="Permalink to &quot;二、獲利品質連動 (Margin Linkage)&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">期間</th><th style="text-align:left;">DRAM 芯片 ASP 變動</th><th style="text-align:left;">凌航毛利率</th><th style="text-align:left;">毛利率變動</th></tr></thead><tbody><tr><td style="text-align:left;">2022H2</td><td style="text-align:left;">下跌</td><td style="text-align:left;">-5.0%</td><td style="text-align:left;">虧損</td></tr><tr><td style="text-align:left;">2023H2</td><td style="text-align:left;">回升</td><td style="text-align:left;">6.1%</td><td style="text-align:left;">+1.1pp vs H1</td></tr><tr><td style="text-align:left;">2024H1</td><td style="text-align:left;">漲價高峰</td><td style="text-align:left;">7.1%</td><td style="text-align:left;">正常</td></tr><tr><td style="text-align:left;">2024H2</td><td style="text-align:left;">漲價趨緩</td><td style="text-align:left;">2.4%</td><td style="text-align:left;"><strong>急降</strong></td></tr><tr><td style="text-align:left;">2025Q1-Q2</td><td style="text-align:left;">溫和漲價</td><td style="text-align:left;">3.6-5.0%</td><td style="text-align:left;">低迷</td></tr><tr><td style="text-align:left;">2025Q4</td><td style="text-align:left;">急遽漲價</td><td style="text-align:left;"><strong>19.12%</strong></td><td style="text-align:left;"><strong>跳升</strong></td></tr></tbody></table><p><strong>深度見解</strong>：</p><ol><li><strong>2024H2 毛利率斷崖</strong>：DRAM 報價趨緩時，凌航毛利率從 7.1% 驟降至 2.4%，顯示其在供應鏈中議價地位弱勢。</li><li><strong>2025Q4 毛利率飆升</strong>：Q4 2025 DRAM 合約價暴漲，凌航毛利率跳升至 19.12%，但改善主要來自庫存利益而非定價權提升。</li></ol><h3 id="三、未來路徑預測-future-path" tabindex="-1">三、未來路徑預測 (Future Path) <a class="header-anchor" href="#三、未來路徑預測-future-path" aria-label="Permalink to &quot;三、未來路徑預測 (Future Path)&quot;">​</a></h3><p>DRAM 報價見頂，2026Q2 營收成長率將從+178%驟降至+30-50%。</p><hr><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析 (Skepticism Mandate) <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析 (Skepticism Mandate)&quot;">​</a></h2><h3 id="空頭風險一-「成本推升型漲價」的本質暴露" tabindex="-1">空頭風險一：「成本推升型漲價」的本質暴露 <a class="header-anchor" href="#空頭風險一-「成本推升型漲價」的本質暴露" aria-label="Permalink to &quot;空頭風險一：「成本推升型漲價」的本質暴露&quot;">​</a></h3><p>凌航的營收成長並非來自「品牌溢價」或「技術護城河」，而是被動享受 DRAM/NAND 原廠漲價的成本轉嫁。關鍵證據：2024H2 當 DRAM 報價漲幅放緩，毛利率從 7.1% 驟降至 2.4%——這是一個「價格接受者」的典型特徵。一旦 DRAM 報價進入下行週期（歷史上 DRAM 景氣循環約 2-3 年），凌航的營收與毛利率將同步承壓，且毛利率跌幅可能大於營收跌幅（因成本具剛性）。</p><h3 id="空頭風險二-2026q1-的「虛假繁榮」" tabindex="-1">空頭風險二：2026Q1 的「虛假繁榮」 <a class="header-anchor" href="#空頭風險二-2026q1-的「虛假繁榮」" aria-label="Permalink to &quot;空頭風險二：2026Q1 的「虛假繁榮」&quot;">​</a></h3><p>2026Q1 營收 +178% YoY 的數字極為亮眼，但此為 DRAM 史上最大單季漲幅（+90-95% QoQ）的產物。歷史教訓：DRAM 市場的超級週期從不持久。2021-2022 年 DRAM 漲價週期中，多家模組商在報價反轉後遭遇「庫存減損」與「毛利率崩塌」雙殺。凌航目前持有 3-4 個月庫存（公司法說會資訊），若 Q2-Q3 2026 DRAM 報價回落 20-30%，高價庫存將侵蝕毛利率。此外，DDR5 現貨價已於 2026 年 3 月出現修正，合約價雖暫穩，但領先指標已轉弱。</p><hr><h2 id="📚-證據來源-veracity-check" tabindex="-1">📚 證據來源 (Veracity Check) <a class="header-anchor" href="#📚-證據來源-veracity-check" aria-label="Permalink to &quot;📚 證據來源 (Veracity Check)&quot;">​</a></h2><ul><li><strong>FinMind</strong>: OK。月營收數據涵蓋 2025 年 5 月至 2026 年 3 月（共 11 個月）；半年報/季報財務數據涵蓋 2022H1 至 2025Q2（含營收、毛利、營業利益、EPS）。資料庫中 2025 年 1-4 月月營收未收錄，以年報/法說會累計營收 77.04 億推算補齊。</li><li><strong>TrendForce/DRAMeXchange</strong>: OK。DRAM 2024 ASP +53% YoY、2025 ASP +35% YoY、2026Q1 合約價 +90-95% QoQ；NAND 2024 ASP +77% YoY、2025 ASP +29% YoY、2026Q1 合約價 +55-60% QoQ。來源：TrendForce 官網 presscenter 及 DRAMeXchange 報導。</li><li><strong>公司資訊/法說會</strong>: OK。產品組合（DRAM 70%/NAND 30%、DDR4 45%/DDR5 55%）、工控佔比 7%、雙品牌策略（Goldkey/Neo Forza）、LTA 長期供貨協議、3-4 月庫存水位。來源：2025 年 7 月上市前業績發表會、多次媒體報導（鉅亨網、工商時報、MoneyDJ）。</li><li><strong>關鍵核對碼</strong>： <ul><li>2024 全年營收 55.08 億 = 2024H1 (24.34 億) + 2024H2 (30.74 億) ✓（FinMind 季報數據交叉驗證）</li><li>2025Q4 毛利率 19.12% ✓（StatementDog/Goodinfo）</li><li>2026Q1 累計營收 39.58 億 = Jan (15.46 億) + Feb (9.81 億) + Mar (14.30 億) ✓（FinMind 月營收）</li><li>TrendForce 2026Q1 DRAM 合約價 +90-95% QoQ ✓（TrendForce 2/2 新聞稿）</li></ul></li></ul>',34)])])}const y=e(d,[["render",n]]);export{x as __pageData,y as default};
